const { userId, gymId } = $input.first().json;

const SUPABASE_URL = $env['SUPABASE_URL'];
const SERVICE_KEY  = $env['SUPABASE_SERVICE_ROLE_KEY'];
const headers = {
  'Authorization': `Bearer ${SERVICE_KEY}`,
  'apikey': SERVICE_KEY
};

async function q(path) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers });
  return res.json();
}

const now = new Date();
const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
const churnCutoff = new Date(Date.now() - 14*24*60*60*1000).toISOString();

const [membership, fitcoins, nextBooking, monthBookings, lastAccess] = await Promise.all([
  q(`memberships?user_id=eq.${userId}&gym_id=eq.${gymId}&status=eq.active&select=id,plan_name,credits,end_date&limit=1`),
  q(`fitcoins?user_id=eq.${userId}&gym_id=eq.${gymId}&select=amount`),
  q(`bookings?user_id=eq.${userId}&gym_id=eq.${gymId}&status=eq.booked&select=class_id,class:class_slots(name,date,start_time)&order=class_slots.date.asc&limit=1`),
  q(`bookings?user_id=eq.${userId}&gym_id=eq.${gymId}&status=eq.completed&created_at=gte.${monthStart}&select=id`),
  q(`access_logs?user_id=eq.${userId}&gym_id=eq.${gymId}&status=eq.allowed&order=scanned_at.desc&limit=1&select=scanned_at`)
]);

const activeMembership = membership[0] || null;
const credits = activeMembership?.credits || 0;
const fitcoinsBalance = (fitcoins || []).reduce((s, f) => s + (f.amount || 0), 0);
const classesThisMonth = (monthBookings || []).length;
const nextClass = nextBooking[0] || null;
const lastAccessAt = lastAccess[0]?.scanned_at || null;

const daysSinceLastClass = lastAccessAt
  ? Math.floor((Date.now() - new Date(lastAccessAt).getTime()) / (1000*60*60*24))
  : 999;
const riskLevel = daysSinceLastClass >= 21 ? 'critical' : daysSinceLastClass >= 14 ? 'high' : daysSinceLastClass >= 7 ? 'medium' : 'low';

return [{ json: {
  user_id: userId,
  gym_id: gymId,
  credits,
  fitcoins_balance: fitcoinsBalance,
  active_membership_id: activeMembership?.id || null,
  membership_expires_at: activeMembership?.end_date || null,
  membership_plan_name: activeMembership?.plan_name || null,
  next_booking_at: nextClass?.class?.date ? `${nextClass.class.date}T${nextClass.class.start_time}` : null,
  next_class_name: nextClass?.class?.name || null,
  classes_this_month: classesThisMonth,
  last_access: lastAccessAt,
  days_inactive: daysSinceLastClass === 999 ? null : daysSinceLastClass,
  risk_level: riskLevel,
  computed_at: new Date().toISOString()
} }];
